// Centers the stroke count based on number of digits
void update_strokes(Adafruit_ILI9341& tft, const String& strokes) {
  tft.fillRect(44, 44, 240, 102, C_BLACK);
  tft.setTextColor(C_WHITE);
  tft.setFont(&Org_01);
  tft.setTextSize(20);

  int len = strokes.length();
  int cursorX = 108;

  if (len == 1) {
    cursorX = (strokes[0] == '1') ? 148 : 108;
  } else if (len == 2) {
    bool d0is1 = (strokes[0] == '1');
    bool d1is1 = (strokes[1] == '1');
    if (d0is1 && d1is1) cursorX = 124;
    else if (d0is1 || d1is1) cursorX = 84;
    else cursorX = 44;
  }

  tft.setCursor(cursorX, 126);
  tft.print(strokes);
}

// Updates strokes, split, and elapsed time together
void update_screen(Adafruit_ILI9341& tft,
                   const String& strokes,
                   const String& split,
                   const String& time) {
  update_strokes(tft, strokes);
  update_split(tft,   split);
  update_timer(tft,   time);
}

