// formats time into "HH:MM:SS"
String formatElapsed(uint32_t seconds) {
  uint32_t h = seconds / 3600;
  uint32_t m = (seconds % 3600) / 60;
  uint32_t s = seconds % 60;
  char buf[12];
  snprintf(buf, sizeof(buf), "%02u:%02u:%02u", h, m, s);
  return String(buf);
}

// formats time into "M:SS" (e.g. 135 → "2:15")
String formatSplit(uint32_t splitSeconds) {
  uint32_t m = splitSeconds / 60;
  uint32_t s = splitSeconds % 60;
  char buf[8];
  snprintf(buf, sizeof(buf), "%u:%02u", m, s);
  return String(buf);
}
